import React from "react";
import { useNavigate } from "react-router-dom";

const Home = () => {
  const navigate = useNavigate();
  const token = localStorage.getItem("token");

  return (
    <div className="flex flex-col items-center justify-center h-screen bg-green-50 text-center p-6">
      <h1 className="text-4xl font-bold text-green-800 mb-6">
        🌱 Welcome to LeafLens
      </h1>
      <p className="text-lg text-gray-700 mb-10 max-w-xl">
        Identify crop diseases instantly by uploading an image of your plant.
        Follow the steps below to get started!
      </p>

      {/* Step cards */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-8 mb-10">
        <div className="p-6 bg-white rounded-2xl shadow-lg border border-green-200 hover:shadow-xl transition">
          <h3 className="text-xl font-semibold text-green-700 mb-3">Step 1️⃣ Register</h3>
          <p className="text-gray-600 mb-4">
            Create your free account to start using LeafLens.
          </p>
          <button
            onClick={() => navigate("/register")}
            className="px-4 py-2 bg-green-600 text-white rounded hover:bg-green-700"
          >
            Register
          </button>
        </div>

        <div className="p-6 bg-white rounded-2xl shadow-lg border border-green-200 hover:shadow-xl transition">
          <h3 className="text-xl font-semibold text-green-700 mb-3">Step 2️⃣ Login</h3>
          <p className="text-gray-600 mb-4">
            Already have an account? Login to access detection features.
          </p>
          <button
            onClick={() => navigate("/login")}
            className="px-4 py-2 bg-green-600 text-white rounded hover:bg-green-700"
          >
            Login
          </button>
        </div>

        <div className="p-6 bg-white rounded-2xl shadow-lg border border-green-200 hover:shadow-xl transition">
          <h3 className="text-xl font-semibold text-green-700 mb-3">Step 3️⃣ Detect</h3>
          <p className="text-gray-600 mb-4">
            Upload a crop leaf image to detect the disease instantly.
          </p>
          <button
            onClick={() => {
              if (token) navigate("/detect");
              else {
                alert("Please login first!");
                navigate("/login");
              }
            }}
            className="px-4 py-2 bg-green-600 text-white rounded hover:bg-green-700"
          >
            Start Detection
          </button>
        </div>
      </div>

      <footer className="text-gray-500 text-sm mt-8">
        🌾 Powered by MERN Stack | Built with ❤️ for Farmers
      </footer>
    </div>
  );
};

export default Home;
